import{_ as n,c as a,a1 as i,o as h}from"./chunks/framework.BDxlaA_J.js";const p=JSON.parse('{"title":"Mạng Máy Tính 101","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/0-core-knowledge/0-Networking-101.md","filePath":"vi/categories/ethical-hacking-labs/0-core-knowledge/0-Networking-101.md"}'),c={name:"vi/categories/ethical-hacking-labs/0-core-knowledge/0-Networking-101.md"};function o(e,t,l,g,r,s){return h(),a("div",null,t[0]||(t[0]=[i(`<h1 id="mang-may-tinh-101" tabindex="-1">Mạng Máy Tính 101 <a class="header-anchor" href="#mang-may-tinh-101" aria-label="Permalink to &quot;Mạng Máy Tính 101&quot;">​</a></h1><blockquote><p>⚠ Mạng 101 là phần giới thiệu đơn giản về các khái niệm mạng quan trọng nhất cho hacking đạo đức. Đây là một chủ đề rất lớn và được khuyến nghị học từ nhiều nguồn khác nhau như khóa học, sách và các chứng chỉ như <a href="https://www.cisco.com/c/en/us/training-events/training-certifications/certifications/associate/ccna.html" target="_blank" rel="noreferrer">Cisco CCNA</a> hoặc <a href="https://www.comptia.org/certifications/network" target="_blank" rel="noreferrer">CompTIA Network+</a>. Ngoài ra có rất nhiều <strong>tài liệu đào tạo miễn phí</strong>, tôi khuyến nghị <a href="https://freetraining.dfirdiva.com/free-networking-training" target="_blank" rel="noreferrer">kiểm tra danh sách này</a> sau.</p></blockquote><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Hiểu các khái niệm cơ bản về mạng</li></ul><h3 id="module-nay-theo-thu-tu" tabindex="-1"><strong>Module này theo thứ tự:</strong> <a class="header-anchor" href="#module-nay-theo-thu-tu" aria-label="Permalink to &quot;**Module này theo thứ tự:**&quot;">​</a></h3><ol><li>Giới thiệu</li><li>Địa chỉ IP và MAC</li><li>Chia mạng con (Subnetting)</li><li>TCP, UDP và Bắt tay 3 bước</li><li>Cổng &amp; Giao thức</li><li>Mô hình OSI</li></ol><h1 id="_1-gioi-thieu" tabindex="-1">1. Giới thiệu <a class="header-anchor" href="#_1-gioi-thieu" aria-label="Permalink to &quot;1. Giới thiệu&quot;">​</a></h1><h2 id="vay-mang-la-gi" tabindex="-1">Vậy mạng là gì? <a class="header-anchor" href="#vay-mang-la-gi" aria-label="Permalink to &quot;Vậy mạng là gì?&quot;">​</a></h2><p>Một mạng bao gồm hai hoặc nhiều máy tính được kết nối với nhau để chia sẻ tài nguyên. Mạng máy tính là nền tảng của truyền thông trong CNTT. Chúng được sử dụng theo nhiều cách khác nhau và có thể bao gồm nhiều loại mạng khác nhau. Mạng máy tính là một tập hợp các máy tính được kết nối với nhau để chúng có thể chia sẻ thông tin. Những ví dụ sớm nhất về mạng máy tính là từ thập niên 1960, nhưng chúng đã đi một chặng đường dài trong nửa thế kỷ kể từ đó.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/5edc8fbef915a17c93fa91c95877134c8fac324c/net2.jpg" alt="net"></p><p><sub><sup>Topology mạng LAN - Mạng SOHO / Nhà nhỏ</sup></sub></p><p><strong>Hai loại mạng phổ biến nhất bao gồm: LAN (Mạng cục bộ) và WAN (Mạng diện rộng)</strong></p><h2 id="cac-loai-topology" tabindex="-1">Các loại topology <a class="header-anchor" href="#cac-loai-topology" aria-label="Permalink to &quot;Các loại topology&quot;">​</a></h2><p>Có nhiều loại mạng khác nhau, có thể được sử dụng cho các mục đích khác nhau và bởi các loại người dùng và tổ chức khác nhau. Dưới đây là một số loại mạng bạn có thể gặp:</p><h3 id="lan-mang-cuc-bo-local-area-network" tabindex="-1">LAN - Mạng Cục Bộ (Local Area Network) <a class="header-anchor" href="#lan-mang-cuc-bo-local-area-network" aria-label="Permalink to &quot;LAN - Mạng Cục Bộ (Local Area Network)&quot;">​</a></h3><ul><li>LAN là một mạng có ranh giới logic và vật lý mà một máy tính có thể phát sóng</li></ul><p align="center"><img width="70%" src="https://www.geocities.ws/alcantara97/starhttt.gif"></p><h3 id="wan-mang-dien-rong-wide-area-network" tabindex="-1">WAN - Mạng Diện Rộng (Wide Area Network) <a class="header-anchor" href="#wan-mang-dien-rong-wide-area-network" aria-label="Permalink to &quot;WAN - Mạng Diện Rộng (Wide Area Network)&quot;">​</a></h3><ul><li>WAN là nhiều mạng LAN hoặc các mạng WAN bổ sung với chức năng định tuyến để kết nối liên thông.</li></ul><p align="center"><img width="70%" src="https://gist.github.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/a3f9b5f3f243467208da83e0d0e543b32233c5d6/wan-topo.jpg"></p><h3 id="man-mang-đo-thi-metropolitan-area-network" tabindex="-1">MAN - Mạng Đô Thị (Metropolitan Area Network) <a class="header-anchor" href="#man-mang-đo-thi-metropolitan-area-network" aria-label="Permalink to &quot;MAN - Mạng Đô Thị (Metropolitan Area Network)&quot;">​</a></h3><p align="center"><img width="70%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f37cec4e00f726cb4be3661f20ccad77751e003a/man-topo.jpg"></p><h3 id="internet" tabindex="-1">Internet <a class="header-anchor" href="#internet" aria-label="Permalink to &quot;Internet&quot;">​</a></h3><p>Kết nối các mạng WAN với nhau cho đến khi hoàn thành toàn bộ thế giới = Internet.</p><ul><li>Giao thức vận hành internet là TCP/IP</li><li>Miễn là bạn sử dụng địa chỉ IPv4 hoặc IPv6 hợp lệ</li></ul><p align="center"><img width="70%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/8c176b8a798fb5749c4391c45015ee5d14d56f13/internet.png"></p><h3 id="intranet" tabindex="-1">Intranet <a class="header-anchor" href="#intranet" aria-label="Permalink to &quot;Intranet&quot;">​</a></h3><p>Nếu bạn sử dụng ngăn xếp TCP/IP và tạo mạng LAN hoặc WAN của riêng mình = Intranet.</p><ul><li>Intranet là mạng riêng vẫn chạy TCP/IP</li></ul><p align="center"><img width="70%" src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/8c176b8a798fb5749c4391c45015ee5d14d56f13/intranet.png"></p><h2 id="cac-thuat-ngu-pho-bien-trong-mang" tabindex="-1">Các thuật ngữ phổ biến trong mạng <a class="header-anchor" href="#cac-thuat-ngu-pho-bien-trong-mang" aria-label="Permalink to &quot;Các thuật ngữ phổ biến trong mạng&quot;">​</a></h2><ul><li><p><strong>Địa chỉ IP (internet protocol)</strong>: địa chỉ mạng của hệ thống trên mạng, còn được gọi là Địa chỉ Logic).</p></li><li><p><strong>Địa chỉ MAC</strong>: địa chỉ MAC hay địa chỉ vật lý định danh duy nhất mỗi máy chủ. Nó được liên kết với Card giao diện mạng (NIC).</p></li><li><p><strong>Hệ thống mở</strong>: hệ thống mở được kết nối vào mạng và sẵn sàng cho giao tiếp.</p></li><li><p><strong>Hệ thống đóng</strong>: hệ thống đóng không được kết nối vào mạng và do đó không thể giao tiếp được.</p></li><li><p><strong>Cổng (Port)</strong>: cổng là kênh qua đó dữ liệu được gửi và nhận.</p></li><li><p><strong>Nút (Nodes)</strong>: nút là thuật ngữ dùng để chỉ bất kỳ thiết bị tính toán nào như máy tính gửi và nhận các gói mạng qua mạng.</p></li><li><p><strong>Gói mạng (Network packets)</strong>: dữ liệu được gửi đến và đi từ các nút trong mạng.</p></li><li><p><strong>Bộ định tuyến (Routers)</strong>: bộ định tuyến là các phần cứng quản lý các gói định tuyến. Chúng xác định nút nào mà thông tin đến và nơi để gửi đến. Một bộ định tuyến có giao thức định tuyến xác định cách nó giao tiếp với các bộ định tuyến khác.</p></li><li><p><strong>Dịch địa chỉ mạng (NAT - Network address translation)</strong>: kỹ thuật mà bộ định tuyến sử dụng để cung cấp dịch vụ internet cho nhiều thiết bị hơn bằng cách sử dụng ít địa chỉ IP công khai hơn. Một bộ định tuyến có địa chỉ IP công khai nhưng các thiết bị kết nối với nó được gán IP riêng mà người ngoài mạng không thể thấy.</p></li><li><p><strong>Giao thức cấu hình máy chủ động (DHCP - Dynamic host configuration protocol)</strong>: gán địa chỉ IP động cho các máy chủ và được duy trì bởi nhà cung cấp dịch vụ internet.</p></li><li><p><strong>Nhà cung cấp dịch vụ internet (ISP - Internet service providers)</strong>: các công ty cung cấp kết nối internet cho mọi người, cả cá nhân và doanh nghiệp cũng như các tổ chức khác.</p></li></ul><h1 id="_2-đia-chi-ip-mac" tabindex="-1">2. Địa chỉ IP &amp; MAC <a class="header-anchor" href="#_2-đia-chi-ip-mac" aria-label="Permalink to &quot;2. Địa chỉ IP &amp; MAC&quot;">​</a></h1><h2 id="đia-chi-ip-la-gi-internet-protocol" tabindex="-1">Địa chỉ IP là gì (Internet Protocol)? <a class="header-anchor" href="#đia-chi-ip-la-gi-internet-protocol" aria-label="Permalink to &quot;Địa chỉ IP là gì (Internet Protocol)?&quot;">​</a></h2><p><img src="https://media.fs.com/images/community/upload/wangEditor/201912/24/_1577182449_2uLs0pQcuT.jpg" alt="ip"></p><p>Địa chỉ IP là một địa chỉ duy nhất xác định một thiết bị trên internet hoặc mạng cục bộ. IP là viết tắt của &quot;Internet Protocol&quot; (Giao thức Internet), là tập hợp các quy tắc điều chỉnh định dạng dữ liệu được gửi qua internet hoặc mạng cục bộ.</p><h2 id="kiem-tra-đia-chi-ip-noi-bo-cua-ban" tabindex="-1">Kiểm tra địa chỉ IP nội bộ của bạn <a class="header-anchor" href="#kiem-tra-đia-chi-ip-noi-bo-cua-ban" aria-label="Permalink to &quot;Kiểm tra địa chỉ IP nội bộ của bạn&quot;">​</a></h2><ol><li>Nếu bạn sử dụng Linux hoặc MacOS bạn có thể mở terminal và nhập lệnh <code>ifconfig</code></li><li>Đối với máy Windows bạn có thể mở cmd prompt hoặc powershell, sau đó nhập <code>ipconfig /all</code></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/5a56240010acbc33026413ad6b5c6f66e9450413/inet.png" alt="inet"></p><ul><li><p>inet IPv4: <code>192.168.64.3</code></p><ul><li><code>inet</code> --&gt; inet (họ giao thức Internet) hiển thị địa chỉ IP nội bộ. Đây là IP phiên bản 4 (IPv4) sử dụng số thập phân 32-bit.</li></ul></li><li><p>inet6 IPv6: <code>fe80::c83b:ccff:fe0e:1069</code></p><ul><li><code>inet6</code> --&gt; Là phiên bản mới của IP (IPv6), sử dụng giá trị thập lục phân 128 bit.</li></ul></li><li><p><code>ether</code> --&gt; Địa chỉ MAC - định danh duy nhất được gán cho bộ điều khiển giao diện mạng (NIC)</p></li></ul><h2 id="them-ve-gia-tri-thap-phan-ipv4" tabindex="-1">Thêm về giá trị thập phân IPv4: <a class="header-anchor" href="#them-ve-gia-tri-thap-phan-ipv4" aria-label="Permalink to &quot;Thêm về giá trị thập phân IPv4:&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IPv4 = 32 bits range (4 octets of 8 bits, from 0-255 each(4))</span></span>
<span class="line"><span></span></span>
<span class="line"><span>11000000.10101000.01000000.00000011   [IPv4 binary]</span></span>
<span class="line"><span>   192  .   168  .   64   .  3        [IPv4 decimal]</span></span></code></pre></div><h3 id="phep-toan-hoc-đang-sau-ipv4" tabindex="-1">Phép toán học đằng sau IPv4: <a class="header-anchor" href="#phep-toan-hoc-đang-sau-ipv4" aria-label="Permalink to &quot;Phép toán học đằng sau IPv4:&quot;">​</a></h3><ul><li>Một octet có 8 bit:</li></ul><table tabindex="0"><thead><tr><th>0 or 1</th><th>0 or 1</th><th>0 or 1</th><th>0 or 1</th><th>0 or 1</th><th>0 or 1</th><th>0 or 1</th><th>0 or 1</th></tr></thead><tbody><tr><td>8th bit</td><td>7th bit</td><td>6th bit</td><td>5th bit</td><td>4th bit</td><td>3rd bit</td><td>2nd bit</td><td>1st bit</td></tr><tr><td>128 (2^7)</td><td>64 (2^6)</td><td>32 (2^5)</td><td>16 (2^4)</td><td>8 (2^3)</td><td>4 (2^2)</td><td>2 (2^1)</td><td>1 (2^0)</td></tr></tbody></table><p>Đây là cách các octet nhị phân chuyển sang thập phân: Bit ngoài cùng bên phải, hay bit ít quan trọng nhất, của một octet có giá trị 2^0. Bit ngay bên trái của nó có giá trị 2^1. Điều này tiếp tục cho đến bit ngoài cùng bên trái, hay bit quan trọng nhất, có giá trị 2^7. Vì vậy nếu tất cả các bit nhị phân đều là 1, giá trị thập phân tương ứng sẽ là 255 như thể hiện ở đây:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  1   1   1   1   1   1   1   1</span></span>
<span class="line"><span>  |   |   |   |   |   |   |   |</span></span>
<span class="line"><span>(128 +64 +32 +16 +8  +4  +2  +1) --&gt; 255 </span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ví dụ chuyển đổi octet:</span></span>
<span class="line"><span>Địa chỉ IP: 192.168.64.3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Để tính octet đầu tiên (192.), từ định dạng nhị phân sang thập phân:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>128  64  32  16  8   4   2   1         </span></span>
<span class="line"><span> |   |   |   |   |   |   |   |</span></span>
<span class="line"><span> 1   1   0   0   0   0   0   0          </span></span>
<span class="line"><span> |   |   |   |   |   |   |   |</span></span>
<span class="line"><span>128+ 64+ 0+  0+  0+  0+  0+  0 = 192   ---&gt; giá trị cuối cùng (octet đầu tiên IPv4 dạng thập phân)</span></span></code></pre></div><ul><li>Lấy IP: <code>192.168.64.3</code></li><li>Octet đầu tiên <code>192</code> ở dạng nhị phân 8 bit là <code>11000000</code>.</li><li>Chỉ bit thứ <code>8</code> và <code>7</code> đang bật và phần còn lại (<code>bit thứ 6 đến 1</code>) đang tắt, nghĩa là giá trị thập phân là tổng cuối cùng của các giá trị này: <code>128 + 64 = 192</code></li></ul><p>⚠️ <strong>Tại sao? Máy tính thấy mọi thứ dưới dạng nhị phân; bật và tắt.</strong></p><h2 id="ipv4-va-ipv6" tabindex="-1">IPv4 và IPv6 <a class="header-anchor" href="#ipv4-va-ipv6" aria-label="Permalink to &quot;IPv4 và IPv6&quot;">​</a></h2><p><img src="https://academy.avast.com/hs-fs/hubfs/New_Avast_Academy/IPv4%20vs.%20IPv6%20What%E2%80%99s%20the%20Difference/IPv4-vs-IPv6.png?width=2750&amp;name=IPv4-vs-IPv6.png" alt="ipv"></p><h2 id="đia-chi-ip-rieng-tu-va-cong-khai" tabindex="-1">Địa chỉ IP Riêng tư và Công khai <a class="header-anchor" href="#đia-chi-ip-rieng-tu-va-cong-khai" aria-label="Permalink to &quot;Địa chỉ IP Riêng tư và Công khai&quot;">​</a></h2><p>Tất cả địa chỉ IPv4 có thể được chia thành hai nhóm lớn: <strong>toàn cầu (hoặc công khai, bên ngoài)</strong> - nhóm này cũng có thể được gọi là &#39;địa chỉ WAN&#39; — những địa chỉ được sử dụng trên Internet, và <strong>địa chỉ riêng tư (hoặc cục bộ, nội bộ)</strong> — những địa chỉ được sử dụng trong mạng cục bộ (LAN).</p><p><img src="https://wiki.teltonika-networks.com/wikibase/images/thumb/a/a7/Sip.png/1100px-Sip.png" alt="priv-pub"></p><h2 id="them-ve-đia-chi-ip-rieng-tu" tabindex="-1">Thêm về địa chỉ <strong>IP Riêng tư</strong>: <a class="header-anchor" href="#them-ve-đia-chi-ip-rieng-tu" aria-label="Permalink to &quot;Thêm về địa chỉ **IP Riêng tư**:&quot;">​</a></h2><p>Các địa chỉ riêng tư (nội bộ) không được định tuyến trên Internet và không có lưu lượng nào có thể gửi đến chúng từ Internet, chúng chỉ hoạt động trong mạng cục bộ. Các địa chỉ riêng tư bao gồm các địa chỉ IP từ các mạng con sau:</p><p><img src="https://66.media.tumblr.com/02a533c1d55ca0ba83e0176168df06ec/tumblr_inline_o4m1taQugo1u4ytoo_1280.jpg" alt="private-ip"></p><h2 id="nat-dich-đia-chi-mang" tabindex="-1">NAT - Dịch Địa Chỉ Mạng <a class="header-anchor" href="#nat-dich-đia-chi-mang" aria-label="Permalink to &quot;NAT - Dịch Địa Chỉ Mạng&quot;">​</a></h2><p>NAT là viết tắt của dịch địa chỉ mạng. Đó là cách ánh xạ nhiều địa chỉ riêng cục bộ thành một địa chỉ công khai trước khi truyền thông tin. Các tổ chức muốn nhiều thiết bị sử dụng một địa chỉ IP duy nhất sử dụng NAT, cũng như hầu hết các bộ định tuyến gia đình.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/8275f73b57bdcb982b1d69aa8d213d2bdb384657/nat2.png" alt="nat2"></p><ol><li><p><strong>NAT Tĩnh (Static NAT)</strong></p><p>Khi địa chỉ cục bộ được chuyển đổi thành địa chỉ công khai, NAT này chọn cùng một địa chỉ. Điều này có nghĩa là sẽ có một địa chỉ IP công khai nhất quán liên kết với bộ định tuyến hoặc thiết bị NAT đó.</p></li><li><p><strong>NAT Động (Dynamic NAT)</strong></p><p>Thay vì chọn cùng một địa chỉ IP mỗi lần, NAT này đi qua một nhóm địa chỉ IP công khai. Điều này dẫn đến việc bộ định tuyến hoặc thiết bị NAT nhận được một địa chỉ khác mỗi lần bộ định tuyến dịch địa chỉ cục bộ sang địa chỉ công khai.</p></li></ol><h3 id="⚠️-đia-chi-ip-hoat-đong-tren-lop-3-cua-mo-hinh-osi" tabindex="-1">⚠️ Địa chỉ IP hoạt động trên <strong>Lớp 3 của Mô hình OSI</strong> <a class="header-anchor" href="#⚠️-đia-chi-ip-hoat-đong-tren-lop-3-cua-mo-hinh-osi" aria-label="Permalink to &quot;⚠️ Địa chỉ IP hoạt động trên **Lớp 3 của Mô hình OSI**&quot;">​</a></h3><p><em>Lưu ý: Module này sẽ giới thiệu mô hình OSI sau.</em></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b9d7f33be654d299f6618feeacb97fc5fd5bd7d2/OSI_L3.png" alt="osi3"></p><h1 id="_3-chia-mang-con-subnetting" tabindex="-1">3. Chia Mạng Con (Subnetting) <a class="header-anchor" href="#_3-chia-mang-con-subnetting" aria-label="Permalink to &quot;3. Chia Mạng Con (Subnetting)&quot;">​</a></h1><h3 id="tai-sao-phai-chia-mang-con" tabindex="-1">Tại sao phải chia mạng con? <a class="header-anchor" href="#tai-sao-phai-chia-mang-con" aria-label="Permalink to &quot;Tại sao phải chia mạng con?&quot;">​</a></h3><p>Cách xây dựng địa chỉ IP khiến cho các bộ định tuyến Internet tương đối đơn giản để tìm đúng mạng để định tuyến dữ liệu vào. Tuy nhiên, trong một mạng lớp A (ví dụ), có thể có hàng triệu thiết bị kết nối, và có thể mất một lúc để dữ liệu tìm đúng thiết bị. Đây là lý do tại sao chia mạng con hữu ích: chia mạng con thu hẹp địa chỉ IP để sử dụng trong một phạm vi thiết bị.</p><p>Vì địa chỉ IP chỉ giới hạn trong việc chỉ ra mạng và địa chỉ thiết bị, địa chỉ IP không thể được sử dụng để chỉ ra gói IP nên đi đến mạng con nào. Các bộ định tuyến trong mạng sử dụng thứ gọi là mặt nạ mạng con để phân loại dữ liệu vào các mạng con.</p><blockquote><p>⚠️ Chia mạng con thực sự quan trọng cho các chuyên gia kiểm thử xâm nhập và hacker tham vọng, cuối cùng bạn sẽ đối mặt với nhiều trường hợp liên quan đến mạng nhỏ hoặc lớn trong các hoạt động tương lai. Hiểu loại địa chỉ IP, phạm vi, số lượng máy chủ có sẵn là rất quan trọng cho bất kỳ phân tích mạng nào.</p></blockquote><h2 id="bang-gian-lan-giup-chia-mang-con-de-hon" tabindex="-1">Bảng gian lận giúp chia mạng con dễ hơn <a class="header-anchor" href="#bang-gian-lan-giup-chia-mang-con-de-hon" aria-label="Permalink to &quot;Bảng gian lận giúp chia mạng con dễ hơn&quot;">​</a></h2><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/5ce4b7daa9c2c10ccd44675eadaceae646e487e2/cyber-mentor-subnetting.png" alt="subnetting"></p><ul><li><p>Bảng gian lận Subnetting của CyberMentor: <a href="https://twitter.com/thecybermentor/status/1211335431406727169" target="_blank" rel="noreferrer">https://twitter.com/thecybermentor/status/1211335431406727169</a></p></li><li><p>Bảng gian lận Subnetting thay thế: <a href="https://nsrc.org/workshops/2009/summer/presentations/day3/subnetting.pdf" target="_blank" rel="noreferrer">https://nsrc.org/workshops/2009/summer/presentations/day3/subnetting.pdf</a></p></li></ul><h2 id="bai-tap" tabindex="-1">Bài tập: <a class="header-anchor" href="#bai-tap" aria-label="Permalink to &quot;Bài tập:&quot;">​</a></h2><p>Chia mạng con giúp trả lời các câu hỏi cơ bản như:</p><ul><li>Xác định địa chỉ mạng và địa chỉ phát sóng</li><li>Có bao nhiêu máy chủ trong phạm vi mạng/máy chủ?</li><li>Mặt nạ nào cho phép máy chủ cụ thể?</li></ul><table tabindex="0"><thead><tr><th>IP range</th><th>Subnet</th><th>Hosts</th><th>Network</th><th>Broadcast</th></tr></thead><tbody><tr><td>192.168.1.16/28</td><td>255.255.255.240</td><td>14</td><td>192.168.1.16</td><td>192.168.1.31</td></tr><tr><td>192.168.0.0/22</td><td>?</td><td>?</td><td>?</td><td>?</td></tr></tbody></table><ul><li>Lấy phạm vi IP <code>192.168.0.0/22</code> liệt kê ở trên</li><li>Bạn có thể dễ dàng tìm ra mặt nạ mạng con bằng cách xem bảng gian lận, bạn có thể thấy cột <code>252</code>. Chỉ cần thay thế giá trị của <code>x</code>. Bạn sẽ được <code>255.255.252.0</code><ul><li>Mặt nạ mạng con có thể là 0, 128, 192, 224, 240, 248, 252, 254 và 255.</li><li>Để hiểu cơ bản về toán học đằng sau các bit, xem hình dưới đây:</li></ul></li></ul><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c1e01e29aedc394f2d75c4ccf57e72606775103a/bits.png" alt="bits"></p><ul><li>Số lượng máy chủ là <code>2^(n) - 2</code>. <ul><li><code>n = số bit tắt</code></li><li>Trong trường hợp này, là 2^10 = 1024 -&gt; 1024 - 2 = <code>1022</code></li></ul></li><li>Phần mạng là giá trị đầu tiên và thấp nhất có thể.</li><li>Địa chỉ phát sóng là giá trị cuối cùng và cao nhất có thể.</li></ul><table tabindex="0"><thead><tr><th>IP range</th><th>Subnet</th><th>Hosts</th><th>Network</th><th>Broadcast</th></tr></thead><tbody><tr><td>192.168.0.0/22</td><td>255.255.252.0</td><td>1022</td><td>192.168.0.0</td><td>192.168.3.255</td></tr></tbody></table><h2 id="thong-tin-lien-quan-khac-ve-ip" tabindex="-1">Thông tin liên quan khác về IP <a class="header-anchor" href="#thong-tin-lien-quan-khac-ve-ip" aria-label="Permalink to &quot;Thông tin liên quan khác về IP&quot;">​</a></h2><ul><li><strong>Các loại địa chỉ IPv4 chính</strong><ul><li><strong>Unicast</strong> - được xử lý bởi một người nhận duy nhất</li><li><strong>Multicast</strong> - được xử lý bởi các thành viên của một nhóm cụ thể</li><li><strong>Broadcast</strong> - được xử lý bởi mọi người trên mạng <ul><li><strong>Limited</strong> - gửi đến mọi hệ thống trong miền (255.255.255.255)</li><li><strong>Directed</strong> - gửi đến tất cả thiết bị trên một mạng con và sử dụng địa chỉ phát sóng đó</li></ul></li></ul></li><li><strong>Mặt nạ mạng con</strong> - xác định bao nhiêu địa chỉ có sẵn trên một mạng con cụ thể <ul><li>Được biểu diễn bằng ba phương pháp <ul><li><strong>Thập phân</strong> - 255.240.0.0</li><li><strong>Nhị phân</strong> - 11111111.11110000.00000000.00000000</li><li><strong>CIDR</strong> - x.x.x.x/12 (trong đó x.x.x.x là một địa chỉ ip trong phạm vi đó)</li></ul></li><li>Nếu tất cả bit trong trường máy chủ đều là 1, địa chỉ đó là địa chỉ phát sóng</li><li>Nếu tất cả đều là 0, đó là địa chỉ mạng</li><li>Bất kỳ kết hợp nào khác cho biết một địa chỉ trong phạm vi</li></ul></li></ul><h1 id="đia-chi-mac" tabindex="-1">Địa chỉ MAC <a class="header-anchor" href="#đia-chi-mac" aria-label="Permalink to &quot;Địa chỉ MAC&quot;">​</a></h1><ul><li>Địa chỉ MAC (Media Access Control) được cung cấp bởi nhà sản xuất Card NIC và cung cấp địa chỉ vật lý của máy tính.</li></ul><p><img src="https://i1.wp.com/learntomato.flashrouters.com/wp-content/uploads/MAC-address-hardware.jpg?resize=560%2C315&amp;ssl=1" alt="macphys"></p><p>Ba byte đầu tiên của địa chỉ MAC ban đầu được gọi là <strong>OUI, hay Định danh Duy nhất của Tổ chức. Mỗi nhà sản xuất thiết bị mạng được gán một OUI, và có thể tự do gán số của riêng họ trong khối đó.</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   OUI     NIC</span></span>
<span class="line"><span>    |       |</span></span>
<span class="line"><span>________ ________</span></span>
<span class="line"><span>00:0c:29:99:98:ca</span></span></code></pre></div><h2 id="kiem-tra-nha-san-xuat-đang-sau-đia-chi-mac" tabindex="-1">Kiểm tra nhà sản xuất đằng sau địa chỉ MAC <a class="header-anchor" href="#kiem-tra-nha-san-xuat-đang-sau-đia-chi-mac" aria-label="Permalink to &quot;Kiểm tra nhà sản xuất đằng sau địa chỉ MAC&quot;">​</a></h2><ol><li><p>Kiểm tra địa chỉ MAC của bạn sử dụng lệnh <code>ifconfig</code> (Linux) hoặc <code>/ipconfig</code> (Windows) <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/214242916f8947f09fc15d5bdde6a668fd4a4c1f/mac2.png" alt="mac"></p></li><li><p>Sao chép và lưu <strong>ba byte đầu tiên</strong> của địa chỉ của bạn. <em>(Ba byte đầu tiên từ hình trên là <code>00:0c:29</code>)</em></p></li><li><p>Xác thực thông tin bằng cách thực hiện <strong>Tra cứu Địa chỉ MAC</strong> trên internet. Ví dụ này sử dụng: <a href="https://aruljohn.com/" target="_blank" rel="noreferrer">https://aruljohn.com/</a><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c82686452d3e671f9a4d351cd5c02171914dd16d/mac2lookup.png" alt="mac2"></p></li><li><p>Như bạn có thể thấy, tra cứu OUI xác định một giao diện mạng ảo được cung cấp bởi VMware</p></li></ol><p><em>Vì vậy, để tóm tắt, <strong>ba byte đầu tiên</strong> được gán cho nhà sản xuất thiết bị mạng và nhà sản xuất gán ba byte cuối cùng của một địa chỉ.</em></p><h3 id="⚠️-đia-chi-mac-hoat-đong-tren-lop-2-cua-mo-hinh-osi" tabindex="-1">⚠️ Địa chỉ MAC hoạt động trên Lớp 2 của Mô hình OSI <a class="header-anchor" href="#⚠️-đia-chi-mac-hoat-đong-tren-lop-2-cua-mo-hinh-osi" aria-label="Permalink to &quot;⚠️ Địa chỉ MAC hoạt động trên Lớp 2 của Mô hình OSI&quot;">​</a></h3><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b9d7f33be654d299f6618feeacb97fc5fd5bd7d2/OSI_L2.png" alt="osil2"></p><h1 id="_4-tcp-ip-udp-va-bat-tay-3-buoc" tabindex="-1">4. TCP/IP, UDP và Bắt tay 3 bước <a class="header-anchor" href="#_4-tcp-ip-udp-va-bat-tay-3-buoc" aria-label="Permalink to &quot;4. TCP/IP, UDP và Bắt tay 3 bước&quot;">​</a></h1><h2 id="giao-thuc-đieu-khien-truyen-tai-giao-thuc-internet-tcp-ip" tabindex="-1">Giao thức Điều khiển Truyền tải/Giao thức Internet (TCP/IP) <a class="header-anchor" href="#giao-thuc-đieu-khien-truyen-tai-giao-thuc-internet-tcp-ip" aria-label="Permalink to &quot;Giao thức Điều khiển Truyền tải/Giao thức Internet (TCP/IP)&quot;">​</a></h2><ul><li>TCP được dùng để làm gì?</li></ul><p>TCP cho phép dữ liệu được truyền giữa các ứng dụng và thiết bị trên mạng. Nó được thiết kế để chia nhỏ một thông báo, chẳng hạn như email, thành các gói dữ liệu để đảm bảo thông báo đến đích thành công và nhanh nhất có thể.</p><ul><li>TCP có nghĩa là gì?</li></ul><p>TCP có nghĩa là Giao thức Điều khiển Truyền tải (Transmission Control Protocol), là một tiêu chuẩn truyền thông để gửi dữ liệu và thông báo qua mạng. TCP là một tiêu chuẩn cơ bản xác định các quy tắc của internet và là giao thức phổ biến được sử dụng để gửi dữ liệu trong truyền thông mạng kỹ thuật số.</p><ul><li>Mô hình TCP/IP bao gồm nhiều loại giao thức, bao gồm: <ul><li>TCP và IP</li><li>Address Resolution Protocol (ARP)</li><li>Internet Control Message Protocol (ICMP)</li><li>Reverse Address Resolution Protocol (RARP)</li><li>User Datagram Protocol (UDP)</li></ul></li></ul><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/bccff9a7c15aa11636c03686ef344ae2d433f699/tcpmodel.png" alt="tcpmod"></p><p><sub><sup>Mô hình TCP/IP</sup></sub></p><p>TCP là giao thức được sử dụng phổ biến nhất trong số các giao thức này và chiếm phần lớn lưu lượng trên mạng TCP/IP. <strong>UDP là một giải pháp thay thế cho TCP không cung cấp sửa lỗi, kém tin cậy hơn và có ít overhead hơn, khiến nó lý tưởng cho phát trực tuyến.</strong></p><h2 id="giao-thuc-datagram-nguoi-dung-udp" tabindex="-1">Giao thức Datagram Người dùng (UDP) <a class="header-anchor" href="#giao-thuc-datagram-nguoi-dung-udp" aria-label="Permalink to &quot;Giao thức Datagram Người dùng (UDP)&quot;">​</a></h2><p>Là một giao thức truyền dữ liệu nhẹ hoạt động trên IP. UDP cung cấp cơ chế để phát hiện dữ liệu bị hỏng trong gói, nhưng nó không cố gắng giải quyết các vấn đề khác phát sinh với gói, chẳng hạn như gói bị mất hoặc out of order. Đó là lý do tại sao UDP đôi khi được gọi là Giao thức Dữ liệu Không Tin cậy (Unreliable Data Protocol). UDP đơn giản nhưng nhanh, ít nhất là so với các giao thức khác hoạt động trên IP. Nó thường được sử dụng cho các ứng dụng nhạy cảm với thời gian (chẳng hạn như phát video trực tiếp) nơi tốc độ quan trọng hơn độ chính xác.</p><ul><li>Trên hệ thống Linux và Unix bạn có thể sử dụng lệnh <code>lsof</code> để xem tiến trình nào đang sử dụng cổng UDP <img src="https://cdn.kastatic.org/ka-perseus-images/edbdf593300fc4a51c60a97998c4d01a51ccd3b1.png" alt="udp"></li></ul><h2 id="đinh-dang-tcp" tabindex="-1">Định dạng TCP <a class="header-anchor" href="#đinh-dang-tcp" aria-label="Permalink to &quot;Định dạng TCP&quot;">​</a></h2><p><img src="https://cdn.kastatic.org/ka-perseus-images/e5fdf560fdb40a1c0b3c3ce96f570e5f00fff161.svg" alt="tc"></p><h2 id="đinh-dang-udp" tabindex="-1">Định dạng UDP <a class="header-anchor" href="#đinh-dang-udp" aria-label="Permalink to &quot;Định dạng UDP&quot;">​</a></h2><p><img src="https://cdn.kastatic.org/ka-perseus-images/9d185d3d44c7ef1e2cd61655e47befb4d383e907.svg" alt="udp"></p><h2 id="bat-tay-tcp" tabindex="-1">Bắt tay TCP <a class="header-anchor" href="#bat-tay-tcp" aria-label="Permalink to &quot;Bắt tay TCP&quot;">​</a></h2><p>TCP sử dụng bắt tay ba bước để thiết lập kết nối tin cậy. Kết nối là full duplex, và cả hai bên đồng bộ hóa (SYN) và xác nhận (ACK) lẫn nhau. Trao đổi bốn cờ này được thực hiện trong ba bước:</p><ol><li>SYN</li><li>SYN-ACK</li><li>ACK</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/bd38a6a2d83ea02a4715d6cb7fd8e0d74af3bd26/3wayhs.jpg" alt="3wayhandshake"></p><p>Cơ chế ba tin nhắn được thiết kế để hai máy tính muốn truyền thông tin qua lại có thể đàm phán các tham số của kết nối trước khi truyền dữ liệu như yêu cầu trình duyệt HTTP.</p><h2 id="them-cac-co-tcp" tabindex="-1">Thêm các cờ TCP <a class="header-anchor" href="#them-cac-co-tcp" aria-label="Permalink to &quot;Thêm các cờ TCP&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Flag</th><th>Tên</th><th>Chức năng</th></tr></thead><tbody><tr><td>SYN</td><td>Đồng bộ hóa</td><td>Được thiết lập trong giao tiếp ban đầu. Đàm phán tham số và số thứ tự</td></tr><tr><td>ACK</td><td>Xác nhận</td><td>Được thiết lập như xác nhận cho cờ SYN. Luôn được thiết lập sau SYN ban đầu</td></tr><tr><td>RST</td><td>Đặt lại</td><td>Buộc chấm dứt kết nối (theo cả hai hướng)</td></tr><tr><td>FIN</td><td>Kết thúc</td><td>Đóng giao tiếp có thứ tự</td></tr><tr><td>PSH</td><td>Đẩy</td><td>Buộc gửi dữ liệu mà không quan tâm đến bộ đệm</td></tr><tr><td>URG</td><td>Khẩn cấp</td><td>Dữ liệu bên trong đang được gửi out of band. Ví dụ là hủy một tin nhắn</td></tr></tbody></table><h2 id="bat-goi-bat-tay-3-buoc-vi-du" tabindex="-1">Bắt gói Bắt tay 3 bước (Ví dụ) <a class="header-anchor" href="#bat-goi-bat-tay-3-buoc-vi-du" aria-label="Permalink to &quot;Bắt gói Bắt tay 3 bước (Ví dụ)&quot;">​</a></h2><ul><li>Hình dưới đây cho thấy các gói bắt tay 3 bước được bắt bởi <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">Wireshark</a></li></ul><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/5213becc28e3f9f46c976d05cd090ffd070ff5d1/wireshark0.png" alt="wireshark"></p><h1 id="_5-cong-giao-thuc" tabindex="-1">5. Cổng &amp; Giao thức <a class="header-anchor" href="#_5-cong-giao-thuc" aria-label="Permalink to &quot;5. Cổng &amp; Giao thức&quot;">​</a></h1><h2 id="cong-la-gi" tabindex="-1">Cổng là gì? <a class="header-anchor" href="#cong-la-gi" aria-label="Permalink to &quot;Cổng là gì?&quot;">​</a></h2><p>Trong mạng máy tính, cổng là một điểm cuối giao tiếp. Ở cấp phần mềm, trong hệ điều hành, cổng là một cấu trúc logic xác định một tiến trình cụ thể hoặc một loại dịch vụ mạng.</p><h2 id="cac-cong-pho-bien-nhat" tabindex="-1">Các cổng phổ biến nhất <a class="header-anchor" href="#cac-cong-pho-bien-nhat" aria-label="Permalink to &quot;Các cổng phổ biến nhất&quot;">​</a></h2><p>Với tư cách là chuyên gia kiểm thử xâm nhập hoặc hacker đạo đức, bạn nên quen thuộc với các cổng và giao thức phổ biến được sử dụng bởi các dịch vụ phổ biến.</p><h3 id="so-hieu-cong" tabindex="-1"><u>Số hiệu Cổng</u> <a class="header-anchor" href="#so-hieu-cong" aria-label="Permalink to &quot;&lt;u&gt;Số hiệu Cổng&lt;/u&gt;&quot;">​</a></h3><ul><li><p><strong>Internet Assigned Numbers Authority</strong> (IANA) - duy trì Registry Tên Dịch vụ và Số hiệu Cổng Giao thức Vận tải liệt kê tất cả các đặt chỗ số hiệu cổng</p></li><li><p>Phạm vi</p><ul><li><p><strong>Cổng được biết đến rộng rãi</strong> - 0 - 1023</p></li><li><p><strong>Cổng đã đăng ký</strong> - 1024 - 49,151</p></li><li><p><strong>Cổng động</strong> - 49,152 - 65,535</p><table tabindex="0"><thead><tr><th>Số hiệu Cổng</th><th>Giao thức</th><th>Giao thức Vận tải</th></tr></thead><tbody><tr><td>20/21</td><td>FTP</td><td>TCP</td></tr><tr><td>22</td><td>SSH</td><td>TCP</td></tr><tr><td>23</td><td>Telnet</td><td>TCP</td></tr><tr><td>25</td><td>SMTP</td><td>TCP</td></tr><tr><td>53</td><td>DNS</td><td>TCP/UDP</td></tr><tr><td>67</td><td>DHCP</td><td>UDP</td></tr><tr><td>69</td><td>TFTP</td><td>UDP</td></tr><tr><td>80</td><td>HTTP</td><td>TCP</td></tr><tr><td>110</td><td>POP3</td><td>TCP</td></tr><tr><td>135</td><td>RPC</td><td>TCP</td></tr><tr><td>137-139</td><td>NetBIOS</td><td>TCP/UDP</td></tr><tr><td>143</td><td>IMAP</td><td>TCP</td></tr><tr><td>161/162</td><td>SNMP</td><td>UDP</td></tr><tr><td>389</td><td>LDAP</td><td>TCP/UDP</td></tr><tr><td>443</td><td>HTTPS</td><td>TCP</td></tr><tr><td>445</td><td>SMB</td><td>TCP</td></tr><tr><td>514</td><td>SYSLOG</td><td>UDP</td></tr></tbody></table></li><li><p>Một dịch vụ được gọi là đang <strong>lắng nghe</strong> khi nó mở cổng cụ thể đó</p></li><li><p>Khi một dịch vụ đã tạo kết nối, cổng ở trạng thái <strong>đã thiết lập</strong></p></li><li><p>Lệnh <strong><code>netstat</code></strong>:</p><ul><li>Hiển thị các cổng mở trên máy tính</li><li><strong>netstat -an</strong> hiển thị kết nối ở dạng số</li><li><strong>netstat -b</strong> hiển thị các file thực thi gắn với cổng mở (chỉ admin)</li></ul></li></ul></li></ul><h1 id="_6-mo-hinh-osi" tabindex="-1">6. Mô hình OSI <a class="header-anchor" href="#_6-mo-hinh-osi" aria-label="Permalink to &quot;6. Mô hình OSI&quot;">​</a></h1><p>Mô hình OSI là một khung mạng giả thuyết sử dụng các giao thức và cơ chế cụ thể trong mỗi lớp. Mô hình này được sử dụng để chia kiến trúc mạng thành bảy lớp khác nhau về mặt khái niệm. Các lớp này là:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3e2dc59e7c341f4d79b2b93bac03fd8378c7ae3a/tcpmo.jpg" alt="osi-model"></p><p>Cũng liên quan đến một số tư thế và cơ chế bảo mật mà chuyên gia bảo mật phải biết để phát hiện và đặt phương pháp bảo mật hiệu quả trong mỗi lớp.</p><h2 id="them-ve-cac-lop" tabindex="-1">Thêm về các Lớp: <a class="header-anchor" href="#them-ve-cac-lop" aria-label="Permalink to &quot;Thêm về các Lớp:&quot;">​</a></h2><h2 id="lop-7-ung-dung" tabindex="-1">Lớp 7 - Ứng dụng <a class="header-anchor" href="#lop-7-ung-dung" aria-label="Permalink to &quot;Lớp 7 - Ứng dụng&quot;">​</a></h2><p><img src="https://www.cloudflare.com/img/learning/ddos/glossary/open-systems-interconnection-model-osi/7-application-layer.svg" alt="l7"></p><ul><li>Đây là lớp duy nhất tương tác trực tiếp với dữ liệu từ người dùng. Các ứng dụng phần mềm như trình duyệt web và ứng dụng email dựa vào lớp ứng dụng để bắt đầu giao tiếp. Nhưng cần nói rõ rằng các ứng dụng phần mềm client không thuộc lớp ứng dụng; thay vào đó lớp ứng dụng chịu trách nhiệm về các giao thức và xử lý dữ liệu mà phần mềm dựa vào để trình bày dữ liệu có ý nghĩa cho người dùng. Các giao thức lớp ứng dụng bao gồm HTTP cũng như SMTP (Simple Mail Transfer Protocol là một trong những giao thức cho phép giao tiếp email).</li></ul><h2 id="lop-6-trinh-bay" tabindex="-1">Lớp 6 - Trình bày <a class="header-anchor" href="#lop-6-trinh-bay" aria-label="Permalink to &quot;Lớp 6 - Trình bày&quot;">​</a></h2><p><img src="https://www.cloudflare.com/img/learning/ddos/glossary/open-systems-interconnection-model-osi/6-presentation-layer.svg" alt="l6"></p><ul><li>Lớp này chủ yếu chịu trách nhiệm chuẩn bị dữ liệu để nó có thể được sử dụng bởi lớp ứng dụng; nói cách khác, lớp 6 làm cho dữ liệu có thể trình bày được cho các ứng dụng tiêu thụ. Lớp trình bày chịu trách nhiệm dịch, mã hóa và nén dữ liệu.</li></ul><h2 id="lop-5-phien" tabindex="-1">Lớp 5 - Phiên <a class="header-anchor" href="#lop-5-phien" aria-label="Permalink to &quot;Lớp 5 - Phiên&quot;">​</a></h2><p><img src="https://www.cloudflare.com/img/learning/ddos/glossary/open-systems-interconnection-model-osi/5-session-layer.svg" alt="l5"></p><ul><li>Đây là lớp chịu trách nhiệm mở và đóng giao tiếp giữa hai thiết bị. Thời gian giữa khi giao tiếp được mở và đóng được gọi là phiên. Lớp phiên đảm bảo rằng phiên mở đủ lâu để truyền tất cả dữ liệu được trao đổi, và sau đó đóng phiên kịp thời để tránh lãng phí tài nguyên.</li></ul><h2 id="lop-4-van-tai" tabindex="-1">Lớp 4 - Vận tải <a class="header-anchor" href="#lop-4-van-tai" aria-label="Permalink to &quot;Lớp 4 - Vận tải&quot;">​</a></h2><p><img src="https://www.cloudflare.com/img/learning/ddos/glossary/open-systems-interconnection-model-osi/4-transport-layer.svg" alt="l4"></p><ul><li><p>Lớp 4 chịu trách nhiệm giao tiếp đầu-cuối giữa hai thiết bị. Bao gồm lấy dữ liệu từ lớp phiên và chia thành các phần gọi là segment trước khi gửi đến lớp 3. Lớp vận tải trên thiết bị nhận chịu trách nhiệm tái lắp ráp các segment thành dữ liệu mà lớp phiên có thể tiêu thụ.</p></li><li><p>Lớp vận tải cũng chịu trách nhiệm kiểm soát luồng và kiểm soát lỗi. Kiểm soát luồng xác định tốc độ truyền tối ưu để đảm bảo rằng người gửi với kết nối nhanh không lấn át người nhận với kết nối chậm. Lớp vận tải thực hiện kiểm soát lỗi ở phía nhận bằng cách đảm bảo dữ liệu nhận được là đầy đủ, và yêu cầu truyền lại nếu không đầy đủ.</p></li></ul><h2 id="lop-3-mang" tabindex="-1">Lớp 3 - Mạng <a class="header-anchor" href="#lop-3-mang" aria-label="Permalink to &quot;Lớp 3 - Mạng&quot;">​</a></h2><p><img src="https://www.cloudflare.com/img/learning/ddos/glossary/open-systems-interconnection-model-osi/3-network-layer.svg" alt="l3"></p><ul><li>Lớp mạng chịu trách nhiệm tạo điều kiện truyền dữ liệu giữa hai mạng khác nhau. Nếu hai thiết bị giao tiếp trên cùng một mạng, thì lớp mạng là không cần thiết. Lớp mạng chia nhỏ các segment từ lớp vận tải thành các đơn vị nhỏ hơn, gọi là gói, trên thiết bị gửi, và tái lắp ráp các gói này trên thiết bị nhận. Lớp mạng cũng tìm đường đi vật lý tốt nhất cho dữ liệu để đến đích; điều này được gọi là định tuyến.</li></ul><h2 id="lop-2-lien-ket-du-lieu" tabindex="-1">Lớp 2 - Liên kết Dữ liệu <a class="header-anchor" href="#lop-2-lien-ket-du-lieu" aria-label="Permalink to &quot;Lớp 2 - Liên kết Dữ liệu&quot;">​</a></h2><p><img src="https://www.cloudflare.com/img/learning/ddos/glossary/open-systems-interconnection-model-osi/2-data-link-layer.svg" alt="l2"></p><ul><li>Lớp liên kết dữ liệu rất giống với lớp mạng, ngoại trừ lớp liên kết dữ liệu tạo điều kiện truyền dữ liệu giữa hai thiết bị trên CÙNG một mạng. Lớp liên kết dữ liệu lấy các gói từ lớp mạng và chia thành các phần nhỏ hơn gọi là frame. Giống như lớp mạng, lớp liên kết dữ liệu cũng chịu trách nhiệm kiểm soát luồng và kiểm soát lỗi trong giao tiếp nội mạng (Lớp vận tải chỉ kiểm soát luồng và kiểm soát lỗi cho giao tiếp liên mạng).</li></ul><h2 id="lop-1-vat-ly" tabindex="-1">Lớp 1 - Vật lý <a class="header-anchor" href="#lop-1-vat-ly" aria-label="Permalink to &quot;Lớp 1 - Vật lý&quot;">​</a></h2><p><img src="https://www.cloudflare.com/img/learning/ddos/glossary/open-systems-interconnection-model-osi/1-physical-layer.svg" alt="l1"></p><ul><li>Lớp này bao gồm các thiết bị vật lý tham gia vào truyền dữ liệu, chẳng hạn như cáp và switch. Đây cũng là lớp nơi dữ liệu được chuyển đổi thành luồng bit, là chuỗi các số 1 và 0. Lớp vật lý của cả hai thiết bị cũng phải đồng ý về quy ước tín hiệu để có thể phân biệt số 1 với số 0 trên cả hai thiết bị.</li></ul>`,152)]))}const u=n(c,[["render",o]]);export{p as __pageData,u as default};
